SELECT
    hsp.HSP_ACCOUNT_ID "HAR"
    , hsp.TOT_CHGS "Total Charges"
    , fc.FINANCIAL_CLASS_NAME "Financial Class"    
    , epm.PAYOR_NAME "Payor"
    , hsptr.TX_AMOUNT "Payment Amount"
FROM HSP_ACCOUNT hsp
    INNER JOIN HSP_TRANSACTIONS hsptr ON hsp.HSP_ACCOUNT_ID = hsptr.HSP_ACCOUNT_ID
        AND hsptr.TX_TYPE_HA_C = 1
    LEFT OUTER JOIN CLARITY_EPM epm ON hsp.PRIMARY_PAYOR_ID = epm.PAYOR_ID
    LEFT OUTER JOIN CLARITY_FC fc ON hsp.ACCT_FIN_CLASS_C = fc.FINANCIAL_CLASS
WHERE 
    hsp.HSP_ACCOUNT_ID IN 
        (429706385,429762298,300563015,429180358,430350599,429601188,430194988,430272755,300930087,601080204
